import{_ as i,o as a,c as e,ai as r}from"./chunks/framework.ampVZV4B.js";const p=JSON.parse('{"title":"阶段四：部署 / 平台化 / MLOps 规划【后期选修】","description":"","frontmatter":{},"headers":[],"relativePath":"tech-system/ai/phase4-mlops-platform.md","filePath":"tech-system/ai/phase4-mlops-platform.md"}'),o={name:"tech-system/ai/phase4-mlops-platform.md"};function s(t,l,h,c,n,d){return a(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="阶段四-部署-平台化-mlops-规划【后期选修】" tabindex="-1">阶段四：部署 / 平台化 / MLOps 规划【后期选修】 <a class="header-anchor" href="#阶段四-部署-平台化-mlops-规划【后期选修】" aria-label="Permalink to “阶段四：部署 / 平台化 / MLOps 规划【后期选修】”">​</a></h1><blockquote><p>这一篇是<strong>完全可选的后期阶段</strong>：当你已经有几个 AI 小项目在本地跑得不错，想进一步部署上线、做成“真正可用的服务”时，可以按这篇来规划。</p></blockquote><hr><h2 id="_1-阶段定位与适合人群" tabindex="-1">1. 阶段定位与适合人群 <a class="header-anchor" href="#_1-阶段定位与适合人群" aria-label="Permalink to “1. 阶段定位与适合人群”">​</a></h2><ul><li>适合： <ul><li>已经完成前面几个阶段（至少有 LLM + MVP Server 小项目）。</li><li>想把自己的“投资助手 / 学习助手 / 问答系统”部署到公网或内网给别人用。</li><li>对 DevOps / 平台化 感兴趣，希望增加简历亮点。</li></ul></li></ul><blockquote><p>对你当前“远程 6000 初/中级岗”的目标，这一阶段是<strong>加分项</strong>，不是必修课。</p></blockquote><hr><h2 id="_2-阶段目标拆解" tabindex="-1">2. 阶段目标拆解 <a class="header-anchor" href="#_2-阶段目标拆解" aria-label="Permalink to “2. 阶段目标拆解”">​</a></h2><ol><li>能把一个简单的 AI Web 服务打包成 Docker 镜像，并在服务器上跑起来。</li><li>知道 CI/CD 的基本流程，能用 GitHub Actions 或类似工具做个最简自动部署。</li><li>能对自己部署的服务做<strong>基础监控</strong>：访问量、错误率、响应时间等。</li></ol><hr><h2 id="_3-时间规划建议-可拉长-按-2-4-周慢慢做" tabindex="-1">3. 时间规划建议（可拉长，按 2～4 周慢慢做） <a class="header-anchor" href="#_3-时间规划建议-可拉长-按-2-4-周慢慢做" aria-label="Permalink to “3. 时间规划建议（可拉长，按 2～4 周慢慢做）”">​</a></h2><h3 id="第-1-周-docker-化你的-ai-服务" tabindex="-1">第 1 周：Docker 化你的 AI 服务 <a class="header-anchor" href="#第-1-周-docker-化你的-ai-服务" aria-label="Permalink to “第 1 周：Docker 化你的 AI 服务”">​</a></h3><ul><li>学习/复盘： <ul><li>Docker 基础概念：镜像 / 容器 / Dockerfile。</li><li>了解如何暴露端口、挂载配置。</li></ul></li><li>实战任务： <ul><li>选你一个现有的小项目（例如“投资助手”或“面试问答助手”）。</li><li>为它写一个最简单的 <code>Dockerfile</code>，包括： <ul><li>拷贝代码。</li><li>安装依赖。</li><li>暴露端口 / 启动命令。</li></ul></li><li>在本机用 <code>docker run</code> 跑起来，确认能访问。</li></ul></li></ul><h3 id="第-2-周-部署到云服务器-平台" tabindex="-1">第 2 周：部署到云服务器 / 平台 <a class="header-anchor" href="#第-2-周-部署到云服务器-平台" aria-label="Permalink to “第 2 周：部署到云服务器 / 平台”">​</a></h3><ul><li>选择一种方式： <ul><li>云服务器（阿里云 / 腾讯云 / 华为云轻量应用）。</li><li>或者托管平台（如 Railway / Render / Fly.io 等）。</li></ul></li><li>实战任务： <ul><li>把打好的镜像推到镜像仓库（Docker Hub 或平台自带仓库）。</li><li>在服务器上拉取镜像并运行，保证： <ul><li>有简单的反向代理（如 Nginx）转发到你的服务。</li><li>能通过浏览器访问简单页面。</li></ul></li></ul></li></ul><h3 id="第-3-4-周-简单-ci-cd-与监控" tabindex="-1">第 3～4 周：简单 CI/CD 与监控 <a class="header-anchor" href="#第-3-4-周-简单-ci-cd-与监控" aria-label="Permalink to “第 3～4 周：简单 CI/CD 与监控”">​</a></h3><ul><li>CI/CD 基础： <ul><li>理解流程：<code>git push</code> → 自动构建镜像 → 自动部署到测试或生产。</li><li>可以用 GitHub Actions 写一条最简 pipeline： <ul><li>代码 push 到 <code>main</code> 分支时，自动构建 Docker 镜像并推送到仓库。</li></ul></li></ul></li><li>监控基础： <ul><li>在日志中记录：请求路径、耗时、错误信息。</li><li>可选：接入一个简单的监控面板或日志服务（如 Grafana + Loki / 第三方日志平台）。</li></ul></li></ul><hr><h2 id="_4-针对不同学习目的的取舍" tabindex="-1">4. 针对不同学习目的的取舍 <a class="header-anchor" href="#_4-针对不同学习目的的取舍" aria-label="Permalink to “4. 针对不同学习目的的取舍”">​</a></h2><h3 id="目的-a-只想-上线给自己或者少数朋友用" tabindex="-1">目的 A：只想“上线给自己或者少数朋友用” <a class="header-anchor" href="#目的-a-只想-上线给自己或者少数朋友用" aria-label="Permalink to “目的 A：只想“上线给自己或者少数朋友用””">​</a></h3><ul><li>做到： <ul><li>本机 Docker 化 + 一台轻量云服务器部署。</li><li>简单 Nginx 反代 + HTTPS（可用免费证书）。</li><li>备份配置和环境变量（避免重装后忘记怎么起）。</li></ul></li></ul><h3 id="目的-b-想在简历上写-有一定-devops-mlops-实践" tabindex="-1">目的 B：想在简历上写“有一定 DevOps / MLOps 实践” <a class="header-anchor" href="#目的-b-想在简历上写-有一定-devops-mlops-实践" aria-label="Permalink to “目的 B：想在简历上写“有一定 DevOps / MLOps 实践””">​</a></h3><ul><li>建议多做： <ul><li>写一份 CI/CD 脚本（哪怕是最简单的自动构建 + 手动部署也行）。</li><li>在文档中整理： <ul><li>架构图（浏览器 → Nginx → AI 服务 → LLM API / 向量库）。</li><li>运维流程（如何更新版本、如何回滚）。</li></ul></li></ul></li></ul><h3 id="目的-c-长期想往-平台工程-ai-平台-方向发展" tabindex="-1">目的 C：长期想往“平台工程 / AI 平台”方向发展 <a class="header-anchor" href="#目的-c-长期想往-平台工程-ai-平台-方向发展" aria-label="Permalink to “目的 C：长期想往“平台工程 / AI 平台”方向发展”">​</a></h3><ul><li>这一阶段只是一个起点，后续可以扩展到： <ul><li>Kubernetes / Helm / 服务网格等。</li><li>模型版本管理、特征存储、在线/离线混合服务等。</li></ul></li></ul><hr><h2 id="_5-如何与整个-ai-学习路线衔接" tabindex="-1">5. 如何与整个 AI 学习路线衔接 <a class="header-anchor" href="#_5-如何与整个-ai-学习路线衔接" aria-label="Permalink to “5. 如何与整个 AI 学习路线衔接”">​</a></h2><ul><li>阶段一：你学会了调用大模型、写 Prompt、做小工具。</li><li>阶段二：你把数据整理成 API，搭了 MVP Server。</li><li>阶段三：你做了更聪明的检索（RAG）和可能的图结构。</li><li>阶段四：你把这些东西<strong>打包成“真正可访问的在线服务”</strong>。</li></ul><p>对你现在的主线来说，可以先把这一篇当作“未来一年内的升级选项”；<br> 等你把 Java / 数据库 / 框架 / 面试这些主线跑顺了，再回头按这篇规划挑一部分做，就能自然形成一个可讲的“AI + 平台实战项目经历”。</p>',29)])])}const m=i(o,[["render",s]]);export{p as __pageData,m as default};
